What does the following program print?

```cpp
#include <iostream>

void inner(int x)
{
    std::cout << x + 1 << '\n';
}

void outer(int x)
{
    inner(x * 2);
}

int main()
{
    outer(3);
    return 0;
}
```

How many active frames does the call stack show when execution is paused at the `std::cout` line in `c` below?

```cpp
#include <iostream>

void c()
{
    std::cout << "here\n";
}

void b() { c(); }
void a() { b(); }

int main()
{
    a();
    return 0;
}
```

A programmer wants to trace the value flowing through this chain but reports that clicking the `helper` frame in the call stack shows a different `val` than expected. What is wrong?

```cpp
#include <iostream>

void helper(int val)
{
    std::cout << val << '\n';
}

void caller(int x)
{
    int val = x + 5;
    helper(val);
}

int main()
{
    caller(10);
    return 0;
}
```
